INSERT INTO offmarket.business_signals (business_id,layer,signal_key,direction,evidence,source,source_url,observed_at) VALUES
('b2a5b6e7-77b9-5614-96da-ff7e54690b83', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 15 yrs in business per company website/search. Owner age estimate 52 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', NULL, '2026-05-15'),('71ca8d28-4ed9-53df-bc65-8bb5f6086b0f', 3, 'successor_check_live_fetch', 'disqualifying', 'Manta and BuildZoom show Kevin Dwayne Carter as sole owner. No second-gen or partner visible from third-party sources. NO live team-page fetch performed; per protocol, A/B candidacy capped without live fetch.', 'web_search_synthesis', NULL, '2026-05-15'),('71ca8d28-4ed9-53df-bc65-8bb5f6086b0f', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 37 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', NULL, '2026-05-15'),('3ff2b09a-15d1-5010-a946-6652db646700', 3, 'successor_check_live_fetch', 'negative', 'Cory Bayless is a named partner since 2015 — clear internal-buy-in successor candidate. NOT a coasting-solo profile.', 'web_search_synthesis', NULL, '2026-05-15'),('3ff2b09a-15d1-5010-a946-6652db646700', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 22 yrs in business per company website/search. Owner age estimate 52 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', NULL, '2026-05-15'),('f2e06ff2-b03f-5d4c-ae1c-9d5b235de059', 3, 'successor_check_live_fetch', 'positive', 'Live fetch — no second-generation Cappadonna family on the public-facing site. Owner Bo D Cappadonna is the only Master Electrician of record per BuildZoom. ~40 yr tenure suggests retirement window.', 'live_website_fetch', 'https://www.cappadonnaelectric.com/', '2026-05-15'),('f2e06ff2-b03f-5d4c-ae1c-9d5b235de059', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 40 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.cappadonnaelectric.com/', '2026-05-15'),('f2e06ff2-b03f-5d4c-ae1c-9d5b235de059', 3, 'no_online_booking', 'positive', 'Site does not offer online booking integration (no Housecall Pro / ServiceTitan / Yapi visible).', 'live_website_fetch', 'https://www.cappadonnaelectric.com/', '2026-05-15'),('46edf89d-1b91-583d-a6fa-273faf13102f', 3, 'successor_check_live_fetch', 'positive', 'Live team page reveals NO second-generation Giffen family employees and NO additional Master Electricians designated. Children Ashley + Zachary mentioned in personal-context only.', 'live_website_fetch', 'https://www.giffenelectric.com/', '2026-05-15'),('46edf89d-1b91-583d-a6fa-273faf13102f', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 35 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.giffenelectric.com/', '2026-05-15'),('46edf89d-1b91-583d-a6fa-273faf13102f', 3, 'no_ev_charger_service', 'positive', 'Site does not list EV-charger install services. In 2026 TX metros, this is a coasting tell — every healthy residential electrical shop offers EV-charger install.', 'live_website_fetch', 'https://www.giffenelectric.com/', '2026-05-15'),('46edf89d-1b91-583d-a6fa-273faf13102f', 3, 'no_online_booking', 'positive', 'Site does not offer online booking integration (no Housecall Pro / ServiceTitan / Yapi visible).', 'live_website_fetch', 'https://www.giffenelectric.com/', '2026-05-15'),('8b0959b9-e787-591f-92f4-716dd97e860b', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 30 yrs in business per company website/search. Owner age estimate 58 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.hurricanelectric.com/home', '2026-05-15'),('6a1a7646-e0ad-5a6a-bdb2-7dee192d15ad', 3, 'successor_check_live_fetch', 'disqualifying', 'No live team-page fetch performed; per protocol cap A/B tier without live fetch.', 'web_search_synthesis', 'https://actionelectric.co/', '2026-05-15'),('6a1a7646-e0ad-5a6a-bdb2-7dee192d15ad', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 32 yrs in business per company website/search. Owner age estimate 58 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://actionelectric.co/', '2026-05-15'),('99191dc6-059c-50c4-80d3-3a0ffdd82928', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 39 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', NULL, '2026-05-15'),('20110f04-af15-57b2-8640-23d2c43b34c0', 3, 'successor_check_live_fetch', 'negative', '4th-generation family business with active Cappadonna family members per Growjo (Matthew Cappadonna). Internal succession clearly in place. NOT a coasting-solo-owner profile.', 'web_search_synthesis', 'https://mid-westelectric.com/', '2026-05-15'),('20110f04-af15-57b2-8640-23d2c43b34c0', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 78 yrs in business per company website/search. Owner age estimate 72 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://mid-westelectric.com/', '2026-05-15'),('935eb297-ec01-52fc-88a3-98782fb4c251', 3, 'successor_check_live_fetch', 'disqualifying', 'Live about-us fetch returned thin content with no team members named. 71 yrs in business almost certainly means a second-generation Keiser is in operations; cannot confirm via live fetch. Per protocol, capping confidence at LOW and tier at C_watch until team page can be fully verified.', 'web_search_synthesis', 'https://keiserelectric.com/', '2026-05-15'),('935eb297-ec01-52fc-88a3-98782fb4c251', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 71 yrs in business per company website/search. Owner age estimate 72 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://keiserelectric.com/', '2026-05-15'),('935eb297-ec01-52fc-88a3-98782fb4c251', 3, 'no_online_booking', 'positive', 'Site does not offer online booking integration (no Housecall Pro / ServiceTitan / Yapi visible).', 'live_website_fetch', 'https://keiserelectric.com/', '2026-05-15'),('7ee97886-8abf-56cc-a36a-56cd84b18d47', 3, 'successor_check_live_fetch', 'positive', 'Live about page reveals NO second-generation Dausin family employees, only one current employee named (Charles Shiley, no title). Copyright 2016 is 10 years stale. However: 150-employee size puts this at $15-25M+ revenue — PLATFORM-SCALE, not SBA-friendly bolt-on; better fit for B_forward to PE community than A_acquire_self.', 'live_website_fetch', 'https://www.dausinelectric.com/', '2026-05-15'),('7ee97886-8abf-56cc-a36a-56cd84b18d47', 1, 'owner_age_verification', 'positive', 'Tenure proxy: 41 yrs in business per company website/search. Owner age estimate 65 from license_tenure + entity formation date. NO OV65 verified.', 'license_tenure_proxy', 'https://www.dausinelectric.com/', '2026-05-15'),('7ee97886-8abf-56cc-a36a-56cd84b18d47', 3, 'stale_copyright_year', 'positive', 'Site footer copyright: 2016 (10 yrs stale)', 'live_website_fetch', 'https://www.dausinelectric.com/', '2026-05-15'),('4d4f7b62-b333-5361-960d-75ad288b96b5', 3, 'successor_check_live_fetch', 'negative', 'Rocky Garcia is named co-owner. Family-succession appears in place. AMBIGUOUS — two separate ''Travis Electric'' entities at the same SA address may exist; without disambiguation cap confidence.', 'web_search_synthesis', 'https://travis-electricservices.com/', '2026-05-15');